        "panopt:quit-request" => {
            self.gate_quit();
            true
        }
        "panopt:close-gate-decision" => {
            self.handle_gate_decision(pipe_message.payload.as_deref());
            true
        }
        "panopt:delete-gate-decision" => {
            self.handle_delete_decision(pipe_message.payload.as_deref());
