            self.spawn_search_dialog();
            true
        }
        "panopt:show-result" => {
            self.handle_search_result(pipe_message.payload.as_deref());
            true
        }
        "panopt:close-search" => {
            self.close_search_pane();
            true
        }
        _ => false,
    }
}

